module asyn_fifo (
    input wclk, rclk, wrstn, rrstn, winc, rinc,
    input [7:0] wdata,
    output wfull, rempty,
    output [7:0] rdata
);

parameter WIDTH = 8;
parameter DEPTH = 16;

reg [3:0] waddr_bin, raddr_bin;
reg [3:0] wptr, rptr;
reg [3:0] wptr_buff, rptr_buff;
reg wen, ren;

dual_port_RAM #(.WIDTH(WIDTH), .DEPTH(DEPTH))
ram (.wclk(wclk), .wenc(wen), .waddr(waddr_bin), .wdata(wdata),
     .rclk(rclk), .renc(ren), .raddr(raddr_bin), .rdata(rdata));

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        waddr_bin <= 0;
    end else if (winc && !wfull) begin
        waddr_bin <= waddr_bin + 1;
    end
end

always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        raddr_bin <= 0;
    end else if (rinc && !rempty) begin
        raddr_bin <= raddr_bin + 1;
    end
end

assign wptr[0] = waddr_bin[0];
assign wptr[1] = waddr_bin[1] ^ waddr_bin[0];
assign wptr[2] = waddr_bin[2] ^ waddr_bin[1];
assign wptr[3] = waddr_bin[3] ^ waddr_bin[2];

assign rptr[0] = raddr_bin[0];
assign rptr[1] = raddr_bin[1] ^ raddr_bin[0];
assign rptr[2] = raddr_bin[2] ^ raddr_bin[1];
assign rptr[3] = raddr_bin[3] ^ raddr_bin[2];

always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr_buff <= 0;
    end else begin
        wptr_buff <= wptr;
    end
end
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr_buff <= 0;
    end else begin
        rptr_buff <= rptr;
    end
end

assign wfull = (wptr_buff == {~rptr_buff[3], rptr_buff[2:0]});
assign rempty = (wptr_buff == rptr_buff);

assign wen = winc && !wfull;
assign ren = rinc && !rempty;
endmodule
